// // This module implements a 5-bit Johnson counter with an asynchronous clear. On each positive clock edge, it produces a 10-bit sequence. When the clear signal is high, the counter clears to 0 immediately, regardless of the clock signal.
module johnson_counter(
    input               clk,
    input               clr,

    output reg [4:0]    count
);

always@(posedge clk or posedge clr) begin
    if (clr)
        count <= 5'b00000;
    else
        count <= {count[3:0], ~count[4]};
end

endmodule
